/// <summary>
/// DAG 节点定义 (Step 行为配置)
/// </summary>
/// <param name="id">
/// 唯一标识
/// </param>
/// <param name="step_type">
/// 步骤类型 (用于插件/工厂分发)
/// </param>
/// <param name="static_params">
/// 静态参数 (直接传递给 Step)
/// </param>
/// <param name="input_mappings">
/// 输入映射 (从 Context 变量池提取参数: Context[Value] -> Param[Key])
/// </param>
/// <param name="output_to_context">
/// 按需上下文映射 (StepOutput.data[Source] -> Context[Target])
/// </param>
/// <param name="output_to_trace">
/// 按需追溯映射 (StepOutput.data[Source] -> TraceData[Target])
/// </param>
/// <param name="edges">
/// 出边集合 (按顺序评估，首个匹配的边即为下一跳)
/// </param>
/// <param name="retry_policy">
/// 重试策略 (可选)
/// </param>
public record DagNode (
    /// <summary>
    /// 唯一标识
    /// </summary>
    string @id, 
    /// <summary>
    /// 步骤类型 (用于插件/工厂分发)
    /// </summary>
    string @stepType, 
    /// <summary>
    /// 静态参数 (直接传递给 Step)
    /// </summary>
    Dictionary<string, GenericValue> @staticParams, 
    /// <summary>
    /// 输入映射 (从 Context 变量池提取参数: Context[Value] -> Param[Key])
    /// </summary>
    Dictionary<string, string> @inputMappings, 
    /// <summary>
    /// 按需上下文映射 (StepOutput.data[Source] -> Context[Target])
    /// </summary>
    DataMapping[] @outputToContext, 
    /// <summary>
    /// 按需追溯映射 (StepOutput.data[Source] -> TraceData[Target])
    /// </summary>
    DataMapping[] @outputToTrace, 
    /// <summary>
    /// 出边集合 (按顺序评估，首个匹配的边即为下一跳)
    /// </summary>
    DagEdge[] @edges, 
    /// <summary>
    /// 重试策略 (可选)
    /// </summary>
    RetryPolicy? @retryPolicy
) {
}

public class FfiConverterTypeDagNode: FfiConverterRustBuffer<DagNode> {
