            + FfiConverterDictionaryStringTypeGenericValue.INSTANCE.AllocationSize(value.@staticParams)
            + FfiConverterDictionaryStringString.INSTANCE.AllocationSize(value.@inputMappings)
            + FfiConverterSequenceTypeDataMapping.INSTANCE.AllocationSize(value.@outputToContext)
