public record DataSource {
    
    public record PlcTag (
        string @name
    ) : DataSource {}
    
    public record PlcRegister (
        string? @deviceName,
        int @address,
        int @offset,
        string @dataType
    ) : DataSource {}
    
    public record LastStepResult (
        string @key
    ) : DataSource {}
    

    
}

public class FfiConverterTypeDataSource : FfiConverterRustBuffer<DataSource>{
    public static FfiConverterRustBuffer<DataSource> INSTANCE = new FfiConverterTypeDataSource();

    public override DataSource Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new DataSource.PlcTag(
                    FfiConverterString.INSTANCE.Read(stream)
                );
            case 2:
                return new DataSource.PlcRegister(
                    FfiConverterOptionalString.INSTANCE.Read(stream),
                    FfiConverterInt32.INSTANCE.Read(stream),
                    FfiConverterInt32.INSTANCE.Read(stream),
                    FfiConverterString.INSTANCE.Read(stream)
                );
            case 3:
                return new DataSource.LastStepResult(
                    FfiConverterString.INSTANCE.Read(stream)
                );
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeDataSource.Read()", value));
        }
    }

    public override int AllocationSize(DataSource value) {
        switch (value) {
            case DataSource.PlcTag variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@name);
            case DataSource.PlcRegister variant_value:
                return 4
                    + FfiConverterOptionalString.INSTANCE.AllocationSize(variant_value.@deviceName)
                    + FfiConverterInt32.INSTANCE.AllocationSize(variant_value.@address)
                    + FfiConverterInt32.INSTANCE.AllocationSize(variant_value.@offset)
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@dataType);
            case DataSource.LastStepResult variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@key);
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeDataSource.AllocationSize()", value));
        }
    }

    public override void Write(DataSource value, BigEndianStream stream) {
        switch (value) {
            case DataSource.PlcTag variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.@name, stream);
                break;
            case DataSource.PlcRegister variant_value:
                stream.WriteInt(2);
                FfiConverterOptionalString.INSTANCE.Write(variant_value.@deviceName, stream);
                FfiConverterInt32.INSTANCE.Write(variant_value.@address, stream);
                FfiConverterInt32.INSTANCE.Write(variant_value.@offset, stream);
                FfiConverterString.INSTANCE.Write(variant_value.@dataType, stream);
                break;
            case DataSource.LastStepResult variant_value:
                stream.WriteInt(3);
                FfiConverterString.INSTANCE.Write(variant_value.@key, stream);
                break;
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeDataSource.Write()", value));
        }
    }
}







public class DatabaseException: UniffiException {
    DatabaseException() : base() {}
    DatabaseException(String @Message) : base(@Message) {}

    // Each variant is a nested class
    
    
    public class RecordNotFound : DatabaseException {
        // Members
        public string @e;

        // Constructor
        public RecordNotFound(
                string @e) : base(
                "@e" + "=" + @e) {

            this.@e = @e;
        }
    }
    
    
    public class RecordDuplicated : DatabaseException {
        // Members
        public string @e;

        // Constructor
        public RecordDuplicated(
                string @e) : base(
                "@e" + "=" + @e) {

            this.@e = @e;
        }
    }
    
    
    public class ConstraintUnique : DatabaseException {
        // Members
        public string @e;

        // Constructor
        public ConstraintUnique(
                string @e) : base(
                "@e" + "=" + @e) {

            this.@e = @e;
        }
    }
    
    
    public class ConstraintForeignKey : DatabaseException {
        // Members
        public string @e;

        // Constructor
        public ConstraintForeignKey(
                string @e) : base(
                "@e" + "=" + @e) {

            this.@e = @e;
        }
    }
    

    
}

public class FfiConverterTypeDatabaseError : FfiConverterRustBuffer<DatabaseException>, CallStatusErrorHandler<DatabaseException> {
    public static FfiConverterTypeDatabaseError INSTANCE = new FfiConverterTypeDatabaseError();

    public override DatabaseException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new DatabaseException.RecordNotFound(
                    FfiConverterString.INSTANCE.Read(stream));
            case 2:
                return new DatabaseException.RecordDuplicated(
                    FfiConverterString.INSTANCE.Read(stream));
            case 3:
                return new DatabaseException.ConstraintUnique(
                    FfiConverterString.INSTANCE.Read(stream));
            case 4:
                return new DatabaseException.ConstraintForeignKey(
                    FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeDatabaseError.Read()", value));
        }
    }

    public override int AllocationSize(DatabaseException value) {
        switch (value) {

            case DatabaseException.RecordNotFound variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@e);

            case DatabaseException.RecordDuplicated variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@e);

            case DatabaseException.ConstraintUnique variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@e);

            case DatabaseException.ConstraintForeignKey variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@e);
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeDatabaseError.AllocationSize()", value));
        }
    }

    public override void Write(DatabaseException value, BigEndianStream stream) {
        switch (value) {
            case DatabaseException.RecordNotFound variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.@e, stream);
                break;
            case DatabaseException.RecordDuplicated variant_value:
                stream.WriteInt(2);
                FfiConverterString.INSTANCE.Write(variant_value.@e, stream);
                break;
            case DatabaseException.ConstraintUnique variant_value:
                stream.WriteInt(3);
                FfiConverterString.INSTANCE.Write(variant_value.@e, stream);
                break;
            case DatabaseException.ConstraintForeignKey variant_value:
                stream.WriteInt(4);
                FfiConverterString.INSTANCE.Write(variant_value.@e, stream);
                break;
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeDatabaseError.Write()", value));
        }
    }
}





/// <summary>
/// Device Event Type
/// </summary>
public enum DeviceEventType: int {
    
    /// <summary>
    /// Indicates a change in the device's operational status (e.g., Online/Offline).
    /// Payload contains a serialized DeviceStatus.
    /// </summary>
    State,
    /// <summary>
    /// Represents raw data received from the device (e.g., a barcode or serial message).
    /// Used by process executors to drive manufacturing logic.
    /// </summary>
    Data,
    /// <summary>
    /// Represents a non-fatal hardware alert or warning (e.g., low ink, paper jam).
    /// reserved for future use.
    /// </summary>
    Alarm
}

public class FfiConverterTypeDeviceEventType: FfiConverterRustBuffer<DeviceEventType> {
    public static FfiConverterTypeDeviceEventType INSTANCE = new FfiConverterTypeDeviceEventType();

    public override DeviceEventType Read(BigEndianStream stream) {
        var value = stream.ReadInt() - 1;
        if (Enum.IsDefined(typeof(DeviceEventType), value)) {
            return (DeviceEventType)value;
        } else {
            throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeDeviceEventType.Read()", value));
        }
    }

    public override int AllocationSize(DeviceEventType value) {
        return 4;
    }

    public override void Write(DeviceEventType value, BigEndianStream stream) {
        stream.WriteInt((int)value + 1);
    }
}







