    public ConcurrentHandleMap<WorkOrderObserver> handleMap = new ConcurrentHandleMap<WorkOrderObserver>();

    public override ulong Lower(WorkOrderObserver value) {
        return handleMap.Insert(value);
    }

    public override WorkOrderObserver Lift(ulong value) {
        if (handleMap.TryGet(value, out var uniffiCallback)) {
            return uniffiCallback;
        } else {
            throw new InternalException($"No callback in handlemap '{value}'");
        }
    }

    public override WorkOrderObserver Read(BigEndianStream stream) {
        return Lift(stream.ReadULong());
    }

    public override int AllocationSize(WorkOrderObserver value) {
        return 8;
    }

    public override void Write(WorkOrderObserver value, BigEndianStream stream) {
        stream.WriteULong(Lower(value));
    }
}




